<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  body {
    background-color: #1a1a1a;
    color: #eee;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100vh;
    margin: 0;
    overflow: hidden;
  }
  h1 { margin-bottom: 20px; font-size: 1.5rem; text-align: center; }
  #controls { margin-bottom: 20px; display: flex; gap: 10px; }
  button {
    padding: 8px 16px;
    background-color: #3b82f6;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    transition: background-color 0.2s;
  }
  button:hover { background-color: #2563eb; }
  button:active { background-color: #1d4ed8; }

  #bars {
    display: flex;
    align-items: flex-end;
    height: 300px;
    width: 100%;
    max-width: 800px;
    gap: 2px;
    padding: 10px;
    background-color: #2a2a2a;
    border-radius: 8px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.3);
  }

  .bar {
    flex: 1;
    background-color: #3b82f6; /* Blue */
    border-radius: 2px 2px 0 0;
    transition: height 0.3s ease-out, background-color 0.2s ease;
    min-height: 5px;
    position: relative;
  }

  .bar.comparing { background-color: #fbbf24; /* Yellow */ }
  .bar.swapping { background-color: #ef4444; /* Red */ }
  .bar.sorted { background-color: #10b981; /* Green */ }
</style>
</head>
<body>

<h1>Sorting Visualizer</h1>

<div id="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>

<div id="bars"></div>

<script>
(function() {
    // State
    let currentArray = [];
    let isSorting = false;

    // Bubble Sort State
    let bubbleIndex = 0;
    let bubblePass = 0;

    // Visual State (for height calculation)
    let minVal = 1;
    let maxVal = 100;
    let range = 99;

    const barsContainer = document.getElementById('bars');
    const sortBtn = document.getElementById('sort');
    const shuffleBtn = document.getElementById('shuffle');
    const resetBtn = document.getElementById('reset');

    // Initialize with a random array on load
    window.onload = () => {
        setArray(generateRandomArray(20));
    };

    function generateRandomArray(size) {
        return Array.from({length: size}, () => Math.floor(Math.random() * 100) + 1);
    }

    // --- API Implementation ---

    window.viz = {
        array: () => currentArray,

        setArray: (a) => {
            currentArray = [...a]; 
            bubbleIndex = 0;
            bubblePass = 0;

            // Update visual state variables
            if (currentArray.length > 0) {
                minVal = Math.min(...currentArray);
                maxVal = Math.max(...currentArray);
                range = maxVal - minVal || 1; 
            } else {
                minVal = 0; maxVal = 0; range = 1;
            }

            render();
        },

        sortStep: () => {
            if (isSorting) return false;

            const n = currentArray.length;
            // If array is empty or single element, it's sorted
            if (n <= 1) return true; 

            let swapped = false;
            const limit = n - bubblePass;

            if (bubbleIndex < limit) {
                let j = bubbleIndex;

                // Compare adjacent elements
                if (currentArray[j] > currentArray[j + 1]) {
                    // Swap in array
                    [currentArray[j], currentArray[j + 1]] = [currentArray[j + 1], currentArray[j]];

                    // Update DOM for swap
                    const barJ = barsContainer.children[j];
                    const barJPlus1 = barsContainer.children[j + 1];

                    if(barJ) {
                        barJ.classList.add('swapping');
                        barJ.style.height = `${((currentArray[j] - minVal) / range) * (barsContainer.clientHeight - 20)}px`;
                    }
                    if(barJPlus1) {
                        barJPlus1.classList.add('swapping');
                        barJPlus1.style.height = `${((currentArray[j+1] - minVal) / range) * (barsContainer.clientHeight - 20)}px`;
                    }

                    // Remove class after transition
                    setTimeout(() => {
                        if(barJ) barJ.classList.remove('swapping');
                        if(barJPlus1) barJPlus1.classList.remove('swapping');
                    }, 300);

                    swapped = true;
                } else {
                    // Comparison step (highlighting)
                    const barJ = barsContainer.children[j];
                    const barJPlus1 = barsContainer.children[j + 1];

                    if(barJ) barJ.classList.add('comparing');
                    if(barJPlus1) barJPlus1.classList.add('comparing');

                    setTimeout(() => {
                        if(barJ) barJ.classList.remove('comparing');
                        if(barJPlus1) barJPlus1.classList.remove('comparing');
                    }, 300);
                }

                bubbleIndex++;
            } else {
                // End of current pass
                bubbleIndex = 0;
                bubblePass++;
            }

            // Check if fully sorted (Bubble sort optimization: n-1 passes guarantee sort)
            if (bubblePass >= n - 1) return true;

            return false;
        },

        sorted: () => {
            const arr = currentArray;
            for (let i = 0; i < arr.length - 1; i++) {
                if (arr[i] > arr[i + 1]) return false;
            }
            return true;
        }
    };

    // --- Rendering ---

    function render() {
        barsContainer.innerHTML = '';
        const arr = currentArray;

        if (arr.length === 0) return;

        // Re-calculate min/max/range just in case, though setArray handles it.
        minVal = Math.min(...arr);
        maxVal = Math.max(...arr);
        range = maxVal - minVal || 1;

        const containerHeight = barsContainer.clientHeight;

        arr.forEach((val, index) => {
            const bar = document.createElement('div');
            bar.className = 'bar';

            // Calculate height percentage relative to max value for visual consistency
            const barHeight = ((val - minVal) / range) * (containerHeight - 20); 

            bar.style.height = `${barHeight}px`;
            barsContainer.appendChild(bar);
        });
    }

    // --- Event Listeners ---

    sortBtn.addEventListener('click', () => {
        isSorting = true;
        while (!window.viz.sorted()) {
            window.viz.sortStep();
        }
        isSorting = false;
    });

    shuffleBtn.addEventListener('click', () => {
        setArray(generateRandomArray(20));
    });

    resetBtn.addEventListener('click', () => {
        setArray(generateRandomArray(20));
    });

})();
</script>
</body>
</html>
